-- Check all payment events for Senyo
SELECT id, participantId, dailyLogId, reason, status, createdAt FROM payment_events WHERE participantId = 90001 ORDER BY createdAt;

-- Check warden messages about Senyo losing a life
SELECT id, sourceEvent, content, createdAt FROM warden_messages WHERE content LIKE '%Senyo%' AND sourceEvent = 'life_lost' ORDER BY createdAt;

